306→      root: {
307→        children: [
308→          {
309→            type: 'paragraph',
310→            children: [
311→              {
312→                type: 'text',
313→                text: payload.plainText,
314→                detail: 0,
315→                format: 0,
316→                mode: 'normal',
317→                style: '',
318→                version: 1,
319→              },
320→            ],
321→            direction: null,
322→            format: '',
323→            indent: 0,
324→            version: 1,
325→          },
326→        ],
327→        direction: null,
328→        format: '',
329→        indent: 0,
330→        type: 'root',
331→        version: 1,
